+import type { AnyColumn } from '~/column.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type WindowValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer U> ? U : unknown;
+type WindowOrderBy = SQLWrapper | SQL.Aliased;
+
+export interface WindowSpec {
+	partitionBy?: WindowOrderBy | WindowOrderBy[];
+	orderBy?: WindowOrderBy | WindowOrderBy[];
+	frame?: WindowFrame;
+}
+
+export class WindowFrameBoundary implements SQLWrapper {
+	constructor(readonly sql: SQL, readonly position: number) {}
+	getSQL(): SQL { return this.sql; }
+}
+
+export const unboundedPreceding = new WindowFrameBoundary(sql`unbounded preceding`, 0);
+export const currentRow = new WindowFrameBoundary(sql`current row`, 2);
+export const unboundedFollowing = new WindowFrameBoundary(sql`unbounded following`, 4);
+
+function validateBoundaryValue(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowFrameBoundary {
+	validateBoundaryValue('preceding', value);
+	return new WindowFrameBoundary(sql.raw(`${value} preceding`), 1);
+}
+
+export function following(value: number): WindowFrameBoundary {
+	validateBoundaryValue('following', value);
+	return new WindowFrameBoundary(sql.raw(`${value} following`), 3);
+}
+
+export interface WindowFrameSpec {
+	from: WindowFrameBoundary;
+	to: WindowFrameBoundary;
+}
+
+export class WindowFrame implements SQLWrapper {
+	constructor(readonly type: 'rows' | 'range', readonly spec: WindowFrameSpec) {}
+	getSQL(): SQL { return sql`${sql.raw(this.type)} between ${this.spec.from} and ${this.spec.to}`; }
+}
+
+function makeFrame(type: 'rows' | 'range', spec: WindowFrameSpec): WindowFrame {
+	if (spec.from.position > spec.to.position) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to"');
+	}
+	return new WindowFrame(type, spec);
+}
+
+export function rows(spec: WindowFrameSpec): WindowFrame { return makeFrame('rows', spec); }
+export function range(spec: WindowFrameSpec): WindowFrame { return makeFrame('range', spec); }
+
+export class WindowFunction<T> extends SQL<T> {
+	over(spec?: WindowSpec | string): SQL<T> {
+		if (typeof spec === 'string') {
+			return sql`${this} over ${sql.identifier(spec)}`;
+		}
+		const partitionBy = spec?.partitionBy === undefined ? [] : (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+		const orderBy = spec?.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+		const partitionBySql = partitionBy.length ? sql` partition by ${sql.join(partitionBy)}` : undefined;
+		const orderBySql = orderBy.length ? sql` order by ${sql.join(orderBy)}` : undefined;
+		const frameSql = spec?.frame ? sql` ${spec.frame}` : undefined;
+		return sql`${this} over (${partitionBySql}${orderBySql}${frameSql})`;
+	}
+}
+
+function windowFunction<T>(name: string, expression?: SQLWrapper): WindowFunction<T> {
+	return new WindowFunction<T>(expression === undefined ? [sql.raw(`${name}()`)] : [sql.raw(`${name}(`), expression.getSQL(), sql.raw(')')]);
+}
+
+function positionalArgument(name: string, value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { return new WindowFunction([sql.raw('ntile('), positionalArgument('ntile', buckets), sql.raw(')')]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<WindowValue<T>, null> | WindowValue<TDefault>>;
+export function lag(expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	return valueFunction('lag', expression, offset, defaultValue);
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<Exclude<WindowValue<T>, null> | WindowValue<TDefault>>;
+export function lead(expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	return valueFunction('lead', expression, offset, defaultValue);
+}
+
+function valueFunction(name: string, expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	const args: SQL[] = [expression.getSQL()];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(defaultValue.getSQL());
+	return new WindowFunction([sql.raw(`${name}(`), sql.join(args, sql`, `), sql.raw(')')]);
+}
+
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null> { return windowFunction('first_value', expression); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null> { return windowFunction('last_value', expression); }
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<WindowValue<T> | null> {
+	return new WindowFunction([sql.raw('nth_value('), expression.getSQL(), sql.raw(', '), positionalArgument('nthValue', nth), sql.raw(')')]);
+}
+
+export function windowSum<T extends SQLWrapper>(expression: T): WindowFunction<string | null> { return windowFunction('sum', expression); }
+export function windowAvg<T extends SQLWrapper>(expression: T): WindowFunction<string | null> { return windowFunction('avg', expression); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null> { return windowFunction('min', expression); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null> { return windowFunction('max', expression); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> {
+	return expression === undefined ? new WindowFunction([sql.raw('count(*)')]) : windowFunction('count', expression);
+}
